module RefModule(count8, clk, rst);input clk;
   input rst;
   output reg [2:0] count8; 


     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@ (posedge clk or posedge dbg_halt) begin

      if (rst == 1)
	count8 <= 3'b000;
      else if (rst == 0) begin
	 count8 <= count8 + 1; 

	 if (count8 == 3'b111) begin 
	    count8 <= 3'b000; 
	 end
      end
   end

endmodule
